#!/usr/bin/env node
// ---------------------------------------------------------------------------
// Email Queue Sender — Sends pre-generated emails from data/email-queue.json
// No Anthropic API calls — emails are generated by Claude Code (Max plan)
// Usage: node scripts/send-email-queue.js [--test] [--run-now]
// ---------------------------------------------------------------------------
require("dotenv").config();
const fs = require("fs");
const path = require("path");
const { sendEmailFrom } = require("../shared/pipeline-gmail");
const { appendRow, readRows } = require("../shared/pipeline-sheets");
const { INBOX_LIMITS } = require("../pipelines/prospect-finder/niche-config");

const TEST_MODE = process.argv.includes("--test");
const QUEUE_PATH = path.join(__dirname, "..", "data", "email-queue.json");
const SHEET_TAB = "Daily Prospects";
const SEND_DELAY_MS = 30000; // 30 seconds between sends

function fmtDate(d) {
  return d.toLocaleDateString("en-CA", { timeZone: "Australia/Melbourne" });
}

function log(msg) {
  const ts = new Date().toLocaleString("en-AU", { timeZone: "Australia/Melbourne", hour12: false });
  console.log(`[${ts}] ${msg}`);
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
async function main() {
  log("=== Email Queue Sender ===");
  log(`Mode: ${TEST_MODE ? "TEST (preview only)" : "PRODUCTION"}`);

  // Load queue
  if (!fs.existsSync(QUEUE_PATH)) {
    log(`Queue file not found: ${QUEUE_PATH}`);
    log("Generate emails first using Claude Code, then save to data/email-queue.json");
    process.exit(1);
  }

  let queue;
  try {
    queue = JSON.parse(fs.readFileSync(QUEUE_PATH, "utf8"));
  } catch (err) {
    log(`Failed to parse queue file: ${err.message}`);
    process.exit(1);
  }

  const pending = queue.filter(e => e.status === "pending");
  log(`Queue loaded: ${queue.length} total, ${pending.length} pending`);

  if (pending.length === 0) {
    log("No pending emails in queue. Nothing to send.");
    return;
  }

  // Load previously contacted emails for dedup
  const contacted = new Set();
  const today = fmtDate(new Date());
  const inboxCounts = { primary: 0, secondary: 0, tertiary: 0 };

  try {
    const sentRows = await readRows(SHEET_TAB);
    for (const row of sentRows.slice(1)) {
      const email = (row[3] || "").toLowerCase().trim();
      if (email) contacted.add(email);

      // Count today's sends per inbox
      const rowDate = (row[0] || "").trim();
      if (rowDate === today) {
        const sentVia = (row[11] || "").toLowerCase().trim();
        if (sentVia === "primary" || sentVia.includes("hello@")) inboxCounts.primary++;
        else if (sentVia === "secondary" || sentVia.includes("outreach@")) inboxCounts.secondary++;
        else if (sentVia === "tertiary" || sentVia.includes("contact@")) inboxCounts.tertiary++;
      }
    }
    log(`Loaded ${contacted.size} previously contacted emails`);
    log(`Today's sends: primary=${inboxCounts.primary}, secondary=${inboxCounts.secondary}, tertiary=${inboxCounts.tertiary}`);
  } catch (err) {
    log(`Warning: Could not load sent history: ${err.message}`);
  }

  const totalRemaining =
    Math.max(0, INBOX_LIMITS.primary - inboxCounts.primary) +
    Math.max(0, INBOX_LIMITS.secondary - inboxCounts.secondary) +
    Math.max(0, INBOX_LIMITS.tertiary - inboxCounts.tertiary);
  log(`Daily capacity remaining: ${totalRemaining}`);

  if (totalRemaining <= 0 && !TEST_MODE) {
    log("All inboxes at daily limit. Exiting.");
    return;
  }

  // Determine active inboxes
  const config = require("../shared/pipeline-config");
  const activeInboxes = ["primary"];
  if (config.gmailUserEmail2 && config.gmailRefreshToken2) activeInboxes.push("secondary");
  if (config.gmailUserEmail3 && config.gmailRefreshToken3) activeInboxes.push("tertiary");
  log(`Active inboxes: ${activeInboxes.join(", ")}`);

  // Process queue
  let emailsSent = 0;
  let emailsFailed = 0;
  let emailsSkipped = 0;
  let emailsDeduped = 0;

  for (let i = 0; i < pending.length; i++) {
    const entry = pending[i];
    const queueIdx = queue.indexOf(entry);
    log(`--- [${i + 1}/${pending.length}] ${entry.company || entry.name} → ${entry.to} ---`);

    // Validate required fields
    if (!entry.to || !entry.subject || !entry.body) {
      log(`  Missing required fields (to/subject/body) — skipping`);
      queue[queueIdx].status = "skipped";
      emailsSkipped++;
      continue;
    }

    // Dedup check
    if (contacted.has(entry.to.toLowerCase())) {
      log(`  Already contacted ${entry.to} — skipping`);
      queue[queueIdx].status = "deduped";
      emailsDeduped++;
      continue;
    }

    // Assign inbox (round-robin, lowest count first)
    let assignedInbox = null;
    const sorted = [...activeInboxes].sort((a, b) => inboxCounts[a] - inboxCounts[b]);
    for (const inbox of sorted) {
      if (inboxCounts[inbox] < INBOX_LIMITS[inbox]) {
        assignedInbox = inbox;
        break;
      }
    }

    if (!assignedInbox && !TEST_MODE) {
      log(`  All inboxes at limit — stopping`);
      break;
    }

    const inboxLabel = assignedInbox || "primary";
    const inboxEmails = {
      primary: config.gmailUserEmail,
      secondary: config.gmailUserEmail2 || config.gmailUserEmail,
      tertiary: config.gmailUserEmail3 || config.gmailUserEmail,
    };
    const fromAddr = inboxEmails[inboxLabel];

    // Send or preview
    if (TEST_MODE) {
      console.log(`  WOULD SEND via ${fromAddr} (${inboxLabel})`);
      console.log(`  Subject: ${entry.subject}`);
      console.log(`  Body: ${entry.body}\n`);
    } else {
      try {
        await sendEmailFrom(inboxLabel, entry.to, entry.subject, entry.body);
        log(`  Sent via ${fromAddr} (${inboxLabel})`);
        emailsSent++;
        inboxCounts[inboxLabel]++;
        contacted.add(entry.to.toLowerCase());
        queue[queueIdx].status = "sent";
        queue[queueIdx].sentAt = new Date().toISOString();
        queue[queueIdx].sentVia = fromAddr;

        // Log to Google Sheets
        try {
          await appendRow(SHEET_TAB, [
            today,
            entry.name || "",
            entry.company || entry.name || "",
            entry.to,
            entry.city || "Melbourne",
            entry.niche || "general",
            (entry.body.split(".")[0] + ".").trim(),
            entry.source || "Claude Code",
            "Yes",
            new Date().toISOString(),
            today,
            fromAddr,
            entry.country || "Australia",
            entry.currency || "AUD",
            "email_only",
            "",
            "none",
            "",
            "none",
          ]);
        } catch (sheetErr) {
          log(`  Sheet log failed: ${sheetErr.message}`);
        }

        // Delay between sends
        if (i < pending.length - 1) {
          await new Promise(r => setTimeout(r, SEND_DELAY_MS));
        }
      } catch (err) {
        log(`  FAILED: ${err.message}`);
        emailsFailed++;
        queue[queueIdx].status = "failed";
        queue[queueIdx].error = err.message;
      }
    }

    // Save queue progress after each email (in case of crash)
    if (!TEST_MODE) {
      fs.writeFileSync(QUEUE_PATH, JSON.stringify(queue, null, 2));
    }
  }

  // Final summary
  log("\n=== SUMMARY ===");
  log(`Pending in queue: ${pending.length}`);
  log(`Sent: ${emailsSent}`);
  log(`Failed: ${emailsFailed}`);
  log(`Skipped (missing fields): ${emailsSkipped}`);
  log(`Deduped (already contacted): ${emailsDeduped}`);
  log(`Final inbox counts: primary=${inboxCounts.primary}, secondary=${inboxCounts.secondary}, tertiary=${inboxCounts.tertiary}`);

  // Save final queue state
  if (!TEST_MODE) {
    fs.writeFileSync(QUEUE_PATH, JSON.stringify(queue, null, 2));
    log(`Queue saved to ${QUEUE_PATH}`);
  }
}

main().catch(err => {
  console.error("Fatal error:", err);
  process.exit(1);
});
